from collections import deque
class Solution:
    def findMedian(self, n, edges, queries):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        ans = []
        for u, v in queries:
            parent = [-1] * n
            pw = [0] * n
            seen = [False] * n
            seen[u] = True
            dq = deque([u])
            while dq:
                cur = dq.popleft()
                if cur == v:
                    break
                for nx, w in adj[cur]:
                    if not seen[nx]:
                        seen[nx] = True
                        parent[nx] = cur
                        pw[nx] = w
                        dq.append(nx)
            path = []
            cur = v
            while cur != -1:
                path.append(cur)
                if cur == u:
                    break
                cur = parent[cur]
            path.reverse()
            total = 0
            for i in range(1, len(path)):
                total += pw[path[i]]
            acc = 0
            chosen = path[0]
            for i in range(len(path)):
                if i > 0:
                    acc += pw[path[i]]
                if 2 * acc >= total:
                    chosen = path[i]
                    break
            ans.append(chosen)
        return ans

