var findMedian = function(n, edges, queries) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v, w] of edges) { adj[u].push([v, w]); adj[v].push([u, w]); }
    const ans = [];
    for (const [u, v] of queries) {
        const parent = new Int32Array(n).fill(-1);
        const pw = new Array(n).fill(0);
        const seen = new Uint8Array(n);
        seen[u] = 1;
        const dq = [u];
        let head = 0;
        while (head < dq.length) {
            const cur = dq[head++];
            if (cur === v) break;
            for (const [nx, w] of adj[cur]) {
                if (!seen[nx]) { seen[nx] = 1; parent[nx] = cur; pw[nx] = w; dq.push(nx); }
            }
        }
        const path = [];
        let cur = v;
        while (cur !== -1) { path.push(cur); if (cur === u) break; cur = parent[cur]; }
        path.reverse();
        let total = 0;
        for (let i = 1; i < path.length; i++) total += pw[path[i]];
        let acc = 0, chosen = path[0];
        for (let i = 0; i < path.length; i++) {
            if (i > 0) acc += pw[path[i]];
            if (2 * acc >= total) { chosen = path[i]; break; }
        }
        ans.push(chosen);
    }
    return ans;
};
